                <div key={index} className='expense-item'>
                    <button className='delete-button'
                    onClick

                    >X</button>

                    <div className='expense-description'>{expense.text}</div>
                    <div className='expense-amount'
                    style={{
                        color: expense.amount > 0 ? '#27ae60' : '#e74c3c'
                    }}>{expense.amount}</div>
                </div>

        ))

        }
        </div>
    )
}

